     1→// ==================== CORE TYPES ====================
     2→
     3→import type { CustomFieldsMap } from './customFields';
     4→
     5→export type ViewMode = 'monthly' | 'weekly' | 'daily' | 'agenda';
     6→export type TaskStatus = 'backlog' | 'todo' | 'inprogress' | 'review' | 'done';
     7→export type TaskPriority = 'low' | 'medium' | 'high';
     8→
     9→// ==================== WIDGET DATA TYPES ====================
    10→
    11→export interface CalendarEvent {
    12→  id: string;
    13→  title: string;
    14→  description?: string;
    15→  startTime?: string; // "14:00" (24-hour format)
    16→  endTime?: string;   // "15:30"
    17→  isAllDay?: boolean; // default true if no times specified
    18→
    19→  // Recurrence
    20→  recurrence?: {
    21→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
    22→    interval: number; // e.g., every 2 weeks
    23→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
    24→    dayOfMonth?: number; // 1-31 (for monthly)
    25→    endType: 'never' | 'after' | 'until';
    26→    endCount?: number; // if endType='after'
    27→    endDate?: string; // if endType='until' (YYYY-MM-DD)
    28→  };
    29→  recurrenceId?: string; // For recurring event instances (parent event ID)
    30→  recurrenceException?: boolean; // True if this instance was edited
    31→
    32→  // Multi-day
    33→  endDate?: string; // YYYY-MM-DD (if different from startDate)
    34→
    35→  // Reminders
    36→  reminders?: number[]; // Minutes before event (e.g., [15, 60])
    37→
    38→  // Location
    39→  location?: string;
    40→
    41→  // Multi-day rendering flags (internal, not persisted)
    42→  _isMultiDayPart?: boolean;
    43→  _isMultiDayFirst?: boolean;
    44→  _isMultiDayLast?: boolean;
    45→}
    46→
    47→export interface CalendarState {
    48→  events: Record<string, CalendarEvent[]>; // dateKey -> array of events
    49→  viewMode: ViewMode;
    50→  currentDate: Date;
    51→}
    52→
    53→export type DependencyType =
    54→  | 'finish-to-start'  // Task B starts when A finishes (default)
    55→  | 'start-to-start'   // Task B starts when A starts
    56→  | 'finish-to-finish' // Task B finishes when A finishes
    57→  | 'start-to-finish'; // Task B finishes when A starts (rare)
    58→
    59→export interface TaskDependency {
    60→  taskId: string;           // ID of dependent task
    61→  type: DependencyType;     // Type of dependency
    62→  lag: number;              // Lag time in days (can be negative for lead)
    63→}
    64→
    65→// Phase 1.4: Baseline snapshot for task (stored in project baseline)
    66→export interface BaselineTask {
    67→  id: string;
    68→  startDate: string | null;
    69→  dueDate: string | null;
    70→  progress: number;
    71→}
    72→
    73→// Phase 1.4: Project baseline snapshot
    74→export interface ProjectBaseline {
    75→  setAt: string;            // ISO date when baseline was set
    76→  tasks: BaselineTask[];    // Snapshot of all tasks at baseline time
    77→}
    78→
    79→// Phase 1.4: Variance status for baseline comparison
    80→export type VarianceStatus = 'ahead' | 'behind' | 'on-track';
    81→
    82→// Phase 3.1: Team member for task assignment
    83→export interface Member {
    84→  id: string;
    85→  name: string;
    86→  email?: string;
    87→  initials: string;        // Auto-generated from name
    88→  avatarColor: string;     // Hex color for avatar background
    89→  createdAt: string;       // ISO date
    90→}
    91→
    92→// Phase 3.2: File attachment for tasks
    93→export interface TaskAttachment {
    94→  id: string;
    95→  taskId: string;
    96→  filename: string;
    97→  fileType: string;        // MIME type (e.g., "image/png", "application/pdf")
    98→  fileSize: number;        // Bytes
    99→  dataUrl: string;         // Base64 data URI
   100→  uploadedAt: string;      // ISO date
   101→  uploadedBy?: string;     // Future: member ID
   102→}
   103→
   104→// Phase 4: Column definition for custom Kanban columns
   105→export interface KanbanColumn {
   106→  id: string;              // e.g., "backlog", "todo", or UUID for custom
   107→  title: string;           // e.g., "Backlog", "In Progress"
   108→  color: string;           // Tailwind class: "bg-status-info"
   109→  order: number;           // For drag-drop reordering
   110→  wipLimit?: number;       // Optional WIP constraint (e.g., 5 tasks max)
   111→}
   112→
   113→// Phase 4: Checklist item for subtasks
   114→export interface ChecklistItem {
   115→  id: string;
   116→  text: string;
   117→  completed: boolean;
   118→  order: number;
   119→  createdAt: string;       // ISO date
   120→}
   121→
   122→// Task Template for Recurring Tasks (P2)
   123→export interface TaskTemplate {
   124→  id: string;
   125→  name: string;                    // Template name (user-defined)
   126→  description: string;             // Template description
   127→  checklist?: ChecklistItem[];     // Checklist items (NOT completion status)
   128→  tags: string[];                  // Tags/labels
   129→  customFields?: CustomFieldsMap;  // Custom field values
   130→  createdAt: string;               // ISO date string
   131→  updatedAt?: string;              // ISO date string
   132→}
   133→
   134→// Phase 5: Subtask - Rich nested tasks within a card
   135→export interface Subtask {
   136→  id: string;
   137→  parentTaskId: string;
   138→  title: string;
   139→  description?: string;
   140→  completed: boolean;
   141→  priority?: TaskPriority;
   142→  dueDate?: string;       // YYYY-MM-DD
   143→  order: number;          // For manual sorting
   144→  createdAt: string;      // ISO date
   145→  completedAt?: string;   // ISO date (when marked complete)
   146→}
   147→
   148→// Phase 5: Simple task dependency (blocks/blocked-by)
   149→export interface SimpleTaskDependency {
   150→  id: string;
   151→  sourceTaskId: string; // Task that blocks
   152→  targetTaskId: string; // Task that is blocked
   153→  createdAt: string;    // ISO date
   154→}
   155→
   156→// Phase 4: Comment for task discussions
   157→export interface TaskComment {
   158→  id: string;
   159→  taskId: string;
   160→  text: string;            // Markdown supported
   161→  author: string;          // For future: user ID, for now: "You"
   162→  createdAt: string;       // ISO date
   163→  updatedAt?: string;      // ISO date (if edited)
   164→}
   165→
   166→// Phase 4: Activity log entry for tracking changes
   167→export interface ActivityLogEntry {
   168→  id: string;
   169→  timestamp: string;       // ISO date
   170→  action: 'created' | 'updated' | 'moved' | 'commented' | 'checklist_updated';
   171→  field?: string;          // e.g., "status", "priority"
   172→  oldValue?: string;
   173→  newValue?: string;
   174→  userId?: string;         // For future: "You" for now
   175→}
   176→
   177→// Undo system: History entry for undoing destructive actions
   178→export interface UndoHistoryEntry {
   179→  id: string;              // Unique ID for this action
   180→  timestamp: string;       // ISO date
   181→  action: 'deleteColumn' | 'replaceAllColumns' | 'deleteTask' | 'bulkDelete';
   182→  description: string;     // Human-readable: "Deleted column 'In Progress'"
   183→  previousState: {
   184→    columns: KanbanColumn[];
   185→    tasks: Task[];
   186→  };
   187→}
   188→
   189→export type EffortEstimate = 1 | 2 | 3 | 5 | 8 | 13; // Story points (Fibonacci)
   190→export type CustomStatus = 'in-review' | 'testing' | 'deployed' | 'blocked'; // Beyond base status
   191→
   192→// Phase 4: Card templates for quick task creation
   193→export interface CardTemplate {
   194→  id: string;
   195→  name: string;
   196→  icon: string;
   197→  description: string;           // Pre-filled description
   198→  defaultPriority: TaskPriority;
   199→  defaultTags: string[];
   200→  defaultColumn?: string;        // Optional default column
   201→  isBuiltIn: boolean;            // System templates vs user-created
   202→}
   203→
   204→export interface TimeTracking {
   205→  estimated?: number;           // Estimated hours
   206→  actual: number;               // Actual hours spent
   207→  activeTimerStart?: string;    // ISO date (null = timer not running)
   208→  timerHistory: Array<{         // Time tracking history log
   209→    id: string;
   210→    startTime: string;          // ISO date
   211→    endTime: string;            // ISO date
   212→    duration: number;           // Seconds
   213→  }>;
   214→}
   215→
   216→export interface Task {
   217→  id: string;
   218→  title: string;
   219→  description: string;
   220→  status: TaskStatus;
   221→  created: string; // ISO date string
   222→  startDate: string | null; // Date string YYYY-MM-DD
   223→  dueDate: string | null; // Date string YYYY-MM-DD
   224→  priority: TaskPriority;
   225→  tags: string[];
   226→  order?: number; // Position within status column for drag-drop
   227→
   228→  // ENHANCED PM FIELDS:
   229→  dependencies?: TaskDependency[]; // Tasks this depends on
   230→  estimatedHours?: number;         // For resource planning
   231→  actualHours?: number;            // For EVM calculations
   232→  progress?: number;               // 0-100 percentage complete
   233→  isMilestone?: boolean;           // True for milestone markers
   234→  assignedTo?: string;             // Resource ID
   235→  baseline?: {                     // Original plan for comparison
   236→    startDate: string;
   237→    dueDate: string;
   238→  };
   239→  isOnCriticalPath?: boolean;      // Calculated field
   240→
   241→  // PHASE 4 FIELDS:
   242→  checklist?: ChecklistItem[];     // Subtasks/checklist
   243→  comments?: TaskComment[];        // Discussion/comments
   244→  activityLog?: ActivityLogEntry[]; // Change history
   245→
   246→  // PHASE 5 FIELDS:
   247→  subtasks?: Subtask[];            // Rich nested tasks
   248→
   249→  // PHASE A (QUICK WINS) FIELDS:
   250→  archivedAt?: string;             // ISO date (when task was archived)
   251→  lastCompletedAt?: string;        // ISO date (when moved to "done" for auto-archive)
   252→  cardNumber?: number;             // Auto-incrementing card number (KAN-1, KAN-2, etc.)
   253→
   254→  // PHASE B (KANBAN PM) FIELDS:
   255→  effort?: EffortEstimate;         // Story points (1, 2, 3, 5, 8, 13)
   256→  customStatus?: CustomStatus;     // Additional status labels (in-review, testing, deployed, blocked)
   257→  timeTracking?: TimeTracking;     // Time tracking with history
   258→
   259→  // RECURRING TASKS FIELDS (P1):
   260→  recurrence?: {
   261→    frequency: 'daily' | 'weekly' | 'monthly' | 'yearly';
   262→    interval: number; // e.g., every 2 weeks
   263→    daysOfWeek?: number[]; // 0=Sun, 1=Mon, etc. (for weekly)
   264→    dayOfMonth?: number; // 1-31 (for monthly)
   265→
   266→    // P3: Ordinal patterns ("first Monday", "last Friday")
   267→    weekOfMonth?: 1 | 2 | 3 | 4 | -1; // -1 = last
   268→    dayOfWeekInMonth?: number; // 0-6 (combined with weekOfMonth)
   269→
   270→    endType: 'never' | 'after' | 'until';
   271→    endCount?: number; // if endType='after'
   272→    endDate?: string; // if endType='until' (YYYY-MM-DD)
   273→    recurFromCompletion?: boolean; // If true, recur from completion date instead of due date (default: false)
   274→    templateId?: string; // P2: Task template to apply to recurring instances
   275→  };
   276→  recurrenceId?: string; // For recurring task instances (parent task ID)
   277→  recurrenceException?: boolean; // True if this instance was edited
   278→  isRecurringParent?: boolean; // True if this is the parent/template task
   279→  nextOccurrence?: string; // YYYY-MM-DD (calculated field)
   280→
   281→  // CUSTOM FIELDS (P2 #3):
   282→  customFields?: CustomFieldsMap; // Custom metadata fields (fieldId -> value)
   283→
   284→  // PHASE 3.1 FIELDS (TEAM COLLABORATION):
   285→  assignees?: string[];           // Array of member IDs assigned to this task
   286→
   287→  // PHASE 3.2 FIELDS (FILE ATTACHMENTS):
   288→  attachments?: TaskAttachment[]; // File attachments for this task
   289→
   290→  // PHASE 3.4 FIELDS (CARD COVERS):
   291→  coverMode?: 'fit' | 'fill'; // Cover image display mode (default: 'fit')
   292→}
   293→
   294→export interface KanbanState {
   295→  tasks: Task[];
   296→  columns: KanbanColumn[];         // Phase 4: Dynamic columns
   297→  // NOTE: dependencies moved to Task.dependencies (task-level instead of global)
   298→  archivedTasks?: Task[];          // Phase A: Archived tasks (separate from active)
   299→  nextCardNumber?: number;         // Phase A: Auto-incrementing counter for card numbers
