  id: string;
  startDate: string | null;
  dueDate: string | null;
  progress: number;
}

// Phase 1.4: Project baseline snapshot
export interface ProjectBaseline {
  setAt: string;            // ISO date when baseline was set
  tasks: BaselineTask[];    // Snapshot of all tasks at baseline time
