     1→/**
     2→ * Backlinks Utility
     3→ * Handles parsing and managing wiki-style links between notes
     4→ * Uses [[Note Title]] syntax similar to Obsidian/Roam
     5→ */
     6→
     7→import type { Note } from '../types/notes';
     8→
     9→/**
    10→ * Pattern to match wiki-style links: [[Note Title]]
    11→ */
    12→const LINK_PATTERN = /\[\[([^\]]+)\]\]/g;
    13→
    14→/**
    15→ * Extract all wiki-style links from text content
    16→ */
    17→export function extractWikiLinks(content: string): string[] {
    18→  const links: string[] = [];
    19→  let match;
    20→  const pattern = new RegExp(LINK_PATTERN.source, 'g');
    21→
    22→  while ((match = pattern.exec(content)) !== null) {
    23→    const linkTitle = match[1].trim();
    24→    if (linkTitle && !links.includes(linkTitle)) {
    25→      links.push(linkTitle);
    26→    }
    27→  }
    28→
    29→  return links;
    30→}
    31→
    32→/**
    33→ * Resolve link titles to note IDs
    34→ */
    35→export function resolveLinksToIds(
    36→  linkTitles: string[],
    37→  allNotes: Record<string, Note>
    38→): string[] {
    39→  const noteIds: string[] = [];
    40→  const notesArray = Object.values(allNotes);
    41→
    42→  linkTitles.forEach((title) => {
    43→    // Try exact title match first
    44→    let foundNote = notesArray.find(
    45→      (note) => note.title.toLowerCase() === title.toLowerCase()
    46→    );
    47→
    48→    // If not found, try partial match
    49→    if (!foundNote) {
    50→      foundNote = notesArray.find(
    51→        (note) => note.title.toLowerCase().startsWith(title.toLowerCase())
    52→      );
    53→    }
    54→
    55→    if (foundNote && !noteIds.includes(foundNote.id)) {
    56→      noteIds.push(foundNote.id);
    57→    }
    58→  });
    59→
    60→  return noteIds;
    61→}
    62→
    63→/**
    64→ * Get all notes that link TO the given note (backlinks)
    65→ */
    66→export function getBacklinks(
    67→  noteId: string,
    68→  noteTitle: string,
    69→  allNotes: Record<string, Note>
    70→): Note[] {
    71→  const backlinks: Note[] = [];
    72→  const titleLower = noteTitle.toLowerCase();
    73→
    74→  Object.values(allNotes).forEach((note) => {
    75→    if (note.id === noteId) return;
    76→
    77→    // Check linkedNotes array
    78→    if (note.linkedNotes?.includes(noteId)) {
    79→      backlinks.push(note);
    80→      return;
    81→    }
    82→
    83→    // Fallback: check content for link pattern
    84→    const links = extractWikiLinks(note.contentText);
    85→    if (links.some((link) => link.toLowerCase() === titleLower)) {
    86→      backlinks.push(note);
    87→    }
    88→  });
    89→
    90→  return backlinks;
    91→}
    92→
    93→/**
    94→ * Update linked notes when content changes
