    96→export function updateLinkedNotes(
    97→  content: string,
    98→  allNotes: Record<string, Note>
    99→): string[] {
   100→  const linkTitles = extractWikiLinks(content);
   101→  return resolveLinksToIds(linkTitles, allNotes);
   102→}
