   914→      convertToWikiLink: (noteId: string, position: number, targetTitle: string) => {
   915→        const state = get();
   916→        const note = state.notes[noteId];
   917→        if (!note) {
   918→          log.warn('Note not found for converting to wiki link', { noteId });
   919→          return;
   920→        }
   921→
   922→        const content = note.contentText;
   923→
   924→        // Find the exact text match at the position
   925→        const titleLength = targetTitle.length;
   926→        const endPosition = position + titleLength;
   927→
   928→        // Extract the text at the position to verify it matches
   929→        const textAtPosition = content.substring(position, endPosition);
   930→
   931→        // Case-insensitive match check
   932→        if (textAtPosition.toLowerCase() !== targetTitle.toLowerCase()) {
   933→          log.warn('Text at position does not match target title', {
   934→            noteId,
   935→            position,
   936→            targetTitle,
   937→            textAtPosition,
   938→          });
   939→          return;
   940→        }
   941→
   942→        // Build the new content with wiki link
   943→        const before = content.substring(0, position);
   944→        const after = content.substring(endPosition);
   945→        const wikiLink = `[[${textAtPosition}]]`; // Preserve original case
   946→        const newContentText = before + wikiLink + after;
   947→
   948→        // Update the note using the updateNote action to ensure proper handling
   949→        get().updateNote(noteId, { contentText: newContentText });
   950→
   951→        log.debug('Converted text to wiki link', {
   952→          noteId,
   953→          position,
   954→          targetTitle,
   955→          originalText: textAtPosition,
   956→        });
   957→      },
