  1099→          return existingNote;
  1100→        }
  1101→
  1102→        // Create new note
  1103→        const newNote = createDailyNoteUtil(date, settings);
  1104→        set((currentState) => ({
  1105→          notes: {
  1106→            ...currentState.notes,
  1107→            [newNote.id]: newNote,
  1108→          },
  1109→          activeNoteId: newNote.id,
  1110→        }));
